import math

t = int(input())
for _ in range(t):
    n = int(input())
    a = list(map(int, input().split()))

    best = float('inf')
    for x in range(3):
        for y in range(3):
            z = 0
            valid = True
            for ai in a:
                # need p<=x, q<=y, r>=0: p+2q+3r=ai
                found = False
                min_rem = float('inf')
                for p in range(x+1):
                    for q in range(y+1):
                        rem = ai - p - 2*q
                        if rem >= 0 and rem % 3 == 0:
                            if rem < min_rem:
                                min_rem = rem
                            found = True
                if found:
                    z = max(z, min_rem // 3)
                else:
                    valid = False
                    break
            if valid:
                best = min(best, x + y + z)
    print(best)
